import { Component, Input } from '@angular/core';

@Component({
  selector: 'app-resume-editor-preview',
  templateUrl: './resume-preview.component.html'
})
export class ResumeEditorPreviewComponent {
  @Input() html = '';
}
<section class="shell-card overflow-hidden p-3 xl:sticky xl:top-24">
  <div class="rounded-[2rem] bg-[#eef1ff] p-4">
    <iframe class="h-[calc(100vh-10rem)] min-h-[980px] w-full rounded-[1.5rem] border-0 bg-white shadow-2xl" [srcdoc]="html"></iframe>
  </div>
</section>
